// «بنك الأسئلة المعرفية» — data only, no UI.
//
// HONESTY CONTRACT (read before adding anything):
//   • Every question here is a fact the author is confident is correct and
//     UNCONTESTED. When a fact is disputed (longest river, first university,
//     population rankings that flip year to year, sectarian rulings, partisan
//     politics) it is simply LEFT OUT rather than guessed at.
//   • Religion questions are limited to structure of the Quran, pillars, seerah
//     events and names that are agreed across the board — no fiqh rulings, no
//     sectarian material, no graded-hadith trivia.
//   • Politics questions are civics and geography only: institutions, capitals,
//     founding dates, published national targets. Never an opinion, never a
//     contested current event.
//   • `explain` is the point of the whole bank: a one-line factual note the
//     player actually learns something from. It must add information, not
//     restate the answer.
//   • `difficulty` is assigned honestly: 1 = common knowledge, 2 = needs some
//     reading, 3 = specialist. It is NOT a knob to spread the counts evenly.
//
// Shape: { id, cat, q, choices:[4], answer:<index>, explain, difficulty:1|2|3 }

export const ALL_CATS = [
  { id: 'religion', ar: 'دينية', en: 'Religion', icon: 'star' },
  { id: 'social', ar: 'اجتماعية', en: 'Society', icon: 'customers' },
  { id: 'geo', ar: 'جغرافيا وسياسة', en: 'Geography & civics', icon: 'pin' },
  { id: 'econ', ar: 'اقتصاد ومال', en: 'Economy & money', icon: 'wallet' },
  { id: 'science', ar: 'علوم وطبيعة', en: 'Science & nature', icon: 'zap' },
  { id: 'history', ar: 'تاريخ', en: 'History', icon: 'clock' },
  { id: 'sport', ar: 'رياضة', en: 'Sport', icon: 'award' },
  { id: 'art', ar: 'فن وثقافة', en: 'Arts & culture', icon: 'theater' },
  { id: 'food', ar: 'طعام وقهوة', en: 'Food & coffee', icon: 'coffee' },
  { id: 'general', ar: 'معلومات عامة', en: 'General knowledge', icon: 'sparkles' },
]

export const CAT_IDS = ALL_CATS.map((c) => c.id)
export const catById = (id) => ALL_CATS.find((c) => c.id === id) || null

const BANK = []

// rows are [question, [4 choices], answerIndex, explanation, difficulty]
function add(cat, rows) {
  rows.forEach((r, i) => {
    BANK.push({ id: `${cat}-${i + 1}`, cat, q: r[0], choices: r[1], answer: r[2], explain: r[3], difficulty: r[4] || 1 })
  })
}

