/**
 * Pull questions without repeating inside a session.
 *
 * @param cat        category id, or 'mix' / falsy for all categories
 * @param difficulty 1|2|3, or an array of allowed levels, or falsy for any
 * @param count      how many to return (fewer if the pool runs out)
 * @param exclude    ids already used this session (array or Set)
 * @param relax      when true (default) and the filtered pool is too small,
 *                   difficulty is widened before repeating anything. Ids in
 *                   `exclude` are NEVER returned — the function returns short
 *                   instead of repeating.
 */
export function getQuestions({ cat, difficulty, count = 10, exclude, relax = true } = {}) {
  const used = exclude instanceof Set ? exclude : new Set(exclude || [])
  const wantCat = cat && cat !== 'mix' ? cat : null
  const levels = difficulty == null ? null : (Array.isArray(difficulty) ? difficulty : [difficulty])

  const base = BANK.filter((q) => !used.has(q.id) && (!wantCat || q.cat === wantCat))
  let pool = levels ? base.filter((q) => levels.includes(q.difficulty)) : base

  if (relax && pool.length < count) {
    // widen difficulty first (keeps the category), then give up gracefully
    const seen = new Set(pool.map((q) => q.id))
    for (const q of base) {
      if (pool.length >= count) break
      if (!seen.has(q.id)) { pool = pool.concat(q); seen.add(q.id) }
    }
  }

  const picked = shuffle(pool).slice(0, count)
  // keep the rising-difficulty feel inside a stage
  return picked.sort((a, b) => a.difficulty - b.difficulty).map(withShuffledChoices)
}

// Shuffling the choices means the same question never sits in the same slot
// twice; the answer index is recomputed, never guessed.
function withShuffledChoices(q) {
  const order = shuffle(q.choices.map((_, i) => i))
  return {
    ...q,
    choices: order.map((i) => q.choices[i]),
    answer: order.indexOf(q.answer),
  }
}

function shuffle(a) {
  const r = [...a]
  for (let i = r.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1))
    ;[r[i], r[j]] = [r[j], r[i]]
  }
  return r
}

/** How many questions exist per category — used by the picker to show counts. */
export function countByCat() {
  const out = {}
  for (const c of ALL_CATS) out[c.id] = 0
  for (const q of BANK) if (out[q.cat] != null) out[q.cat] += 1
  return out
}

export const QUESTIONS = BANK
export const TOTAL_QUESTIONS = BANK.length
